import { z } from 'zod';

export const LabelCreateSchema = z.object({
  name: z.string().min(1).max(30),
  color: z.string().regex(/^#[0-9A-F]{6}$/i).optional(),
  description: z.string().optional(),
  teamId: z.string().optional(), // null for workspace-wide
  parentId: z.string().optional(), // For label hierarchy
});

export type LabelCreate = z.infer<typeof LabelCreateSchema>;

export const LabelUpdateSchema = z.object({
  name: z.string().min(1).max(30).optional(),
  color: z.string().regex(/^#[0-9A-F]{6}$/i).optional(),
  description: z.string().optional(),
});

export type LabelUpdate = z.infer<typeof LabelUpdateSchema>;

export const LabelFilterSchema = z.object({
  teamId: z.string().nullable().optional(), // null for workspace-only
  includeArchived: z.boolean().default(false),
  searchQuery: z.string().optional(),
});

export type LabelFilter = z.infer<typeof LabelFilterSchema>;

export const BulkLabelOperationSchema = z.object({
  issueIds: z.array(z.string()).min(1),
  labelId: z.string().min(1),
});

export type BulkLabelOperation = z.infer<typeof BulkLabelOperationSchema>;

import { z } from 'zod';
import { PaginationSchema } from '@atoms/types/common';

// Valid emoji reactions for comments
export const VALID_EMOJI_REACTIONS = ['👍', '👎', '❤️', '🎉', '👀'] as const;

export const CommentCreateSchema = z.object({
  issueId: z.string().min(1, 'Issue ID is required'),
  body: z.string().min(1, 'Comment body is required'),
  parentId: z.string().optional(), // For threaded comments
  createAsUser: z.string().optional(), // For OAuth apps
  displayIconUrl: z.string().url('Invalid URL format').optional(),
});

export const CommentUpdateSchema = z.object({
  body: z.string().min(1, 'Comment body is required'),
});

export const CommentFilterSchema = z.object({
  issueId: z.string().optional(),
  userId: z.string().optional(),
  parentId: z.string().optional(),
});

export const ReactionCreateSchema = z.object({
  commentId: z.string().min(1, 'Comment ID is required'),
  emoji: z.enum(VALID_EMOJI_REACTIONS, { 
    message: `Invalid emoji. Must be one of: ${VALID_EMOJI_REACTIONS.join(', ')}` 
  }),
});

// Type definitions
export type CommentCreate = z.infer<typeof CommentCreateSchema>;
export type CommentUpdate = z.infer<typeof CommentUpdateSchema>;
export type CommentFilter = z.infer<typeof CommentFilterSchema>;
export type ReactionCreate = z.infer<typeof ReactionCreateSchema>;
export type Pagination = z.infer<typeof PaginationSchema>;

// Mention parsing result
export interface MentionParseResult {
  users: string[];
  issues: string[];
}

import { z } from 'zod';

export const CycleCreateSchema = z.object({
  name: z.string().min(1),
  teamId: z.string(),
  startsAt: z.string().datetime(),
  endsAt: z.string().datetime(),
  description: z.string().optional(),
});

export type CycleCreate = z.infer<typeof CycleCreateSchema>;

export const CycleUpdateSchema = z.object({
  name: z.string().optional(),
  description: z.string().optional(),
  startsAt: z.string().datetime().optional(),
  endsAt: z.string().datetime().optional(),
});

export type CycleUpdate = z.infer<typeof CycleUpdateSchema>;

export const CycleFilterSchema = z.object({
  teamId: z.string().optional(),
  isActive: z.boolean().optional(),
  includeArchived: z.boolean().default(false),
});

export type CycleFilter = z.infer<typeof CycleFilterSchema>;

export interface CycleProgress {
  completedPoints: number;
  totalPoints: number;
  percentComplete: number;
  completedIssues: number;
  totalIssues: number;
}

