import { 
  IssueLabel, 
  IssueLabelConnection,
  Issue,
  IssueConnection,
  LinearDocument
} from '@linear/sdk';

type LabelCreateInput = LinearDocument.IssueLabelCreateInput;
type LabelUpdateInput = LinearDocument.IssueLabelUpdateInput;
type LinearLabelFilter = LinearDocument.IssueLabelFilter;
type LinearIssueFilter = LinearDocument.IssueFilter;

import { linearClient } from '@atoms/client/linear-client';
import { logger } from '@atoms/shared/logger';
import { 
  NotFoundError, 
  ValidationError, 
  BatchOperationResult,
  Pagination 
} from '@atoms/types/common';
import { 
  LabelCreate, 
  LabelUpdate, 
  LabelFilter,
  LabelCreateSchema,
  LabelUpdateSchema,
  BulkLabelOperation,
  BulkLabelOperationSchema
} from './schemas';

export class LabelService {
  private client = linearClient.getClient();

  async create(data: LabelCreate): Promise<IssueLabel> {
    try {
      // Validate input
      const validatedData = LabelCreateSchema.parse(data);

      logger.debug('Creating label', validatedData);

      const input: LabelCreateInput = {
        name: validatedData.name,
        color: validatedData.color,
        description: validatedData.description,
        teamId: validatedData.teamId,
        parentId: validatedData.parentId,
      };

      const payload = await this.client.createLabel(input);

      if (!payload.success || !payload.issueLabel) {
        throw new ValidationError('Failed to create label');
      }

      const label = await payload.issueLabel;
      logger.success(`Label created: ${label.name}`);

      return label;
    } catch (error) {
      if (error instanceof ValidationError) {
        throw error;
      }
      logger.error('Failed to create label', error);
      throw error;
    }
  }

  async get(id: string): Promise<IssueLabel | null> {
    try {
      logger.debug(`Fetching label: ${id}`);
      const label = await this.client.issueLabel(id);
      return label;
    } catch (error) {
      logger.debug(`Label not found: ${id}`);
      return null;
    }
  }

  async getByName(name: string, teamId?: string): Promise<IssueLabel | null> {
    try {
      logger.debug(`Fetching label by name: ${name}`, { teamId });

      const filter: any = {
        name: { eq: name },
      };

      if (teamId === undefined) {
        // Workspace label - no team filter
        filter.team = null;
      } else {
        // Team-specific label
        filter.team = { id: { eq: teamId } };
      }

      const labels = await this.client.issueLabels({
        filter,
        first: 1
      });

      const nodes = await labels.nodes;
      return nodes.length > 0 ? nodes[0] : null;
    } catch (error) {
      logger.debug(`Label not found: ${name}`);
      return null;
    }
  }

  async update(id: string, data: LabelUpdate): Promise<IssueLabel> {
    try {
      // Validate input
      const validatedData = LabelUpdateSchema.parse(data);

      logger.debug(`Updating label: ${id}`, validatedData);

      const label = await this.get(id);
      if (!label) {
        throw new NotFoundError('Label', id);
      }

      const input: LabelUpdateInput = {
        name: validatedData.name,
        color: validatedData.color,
        description: validatedData.description,
      };

      const payload = await this.client.updateLabel(id, input);

      if (!payload.success || !payload.issueLabel) {
        throw new ValidationError('Failed to update label');
      }

      const updatedLabel = await payload.issueLabel;
      logger.success(`Label updated: ${updatedLabel.name}`);

      return updatedLabel;
    } catch (error) {
      if (error instanceof NotFoundError || error instanceof ValidationError) {
        throw error;
      }
      logger.error(`Failed to update label ${id}`, error);
      throw error;
    }
  }

  async delete(id: string): Promise<boolean> {
    try {
      logger.debug(`Deleting label: ${id}`);

      const label = await this.get(id);
      if (!label) {
        throw new NotFoundError('Label', id);
      }

      const payload = await this.client.deleteLabel(id);

      if (!payload.success) {
        throw new ValidationError('Failed to delete label');
      }

      logger.success(`Label deleted: ${id}`);
      return true;
    } catch (error) {
      if (error instanceof NotFoundError) {
        throw error;
      }
      logger.error(`Failed to delete label ${id}`, error);
      throw error;
    }
  }

  async list(filter?: LabelFilter, pagination?: Pagination): Promise<IssueLabelConnection> {
    try {
      logger.debug('Listing labels', { filter, pagination });

      const linearFilter: LinearLabelFilter = {};

      if (filter) {
        if (filter.teamId === null) {
          // Workspace labels only
          linearFilter.team = null;
        } else if (filter.teamId) {
          // Team-specific labels
          linearFilter.team = { id: { eq: filter.teamId } };
        }

        if (filter.searchQuery) {
          linearFilter.name = { contains: filter.searchQuery };
        }
      }

      const labels = await this.client.issueLabels({
        filter: linearFilter,
        includeArchived: filter?.includeArchived,
        first: pagination?.first,
        after: pagination?.after,
        before: pagination?.before,
        last: pagination?.last,
      });

      return labels;
    } catch (error) {
      logger.error('Failed to list labels', error);
      throw error;
    }
  }

  async listByTeam(teamId: string): Promise<IssueLabelConnection> {
    try {
      logger.debug(`Listing labels for team: ${teamId}`);

      const labels = await this.client.issueLabels({
        filter: {
          team: { id: { eq: teamId } },
        },
        includeArchived: false,
      });

      return labels;
    } catch (error) {
      logger.error(`Failed to list labels for team ${teamId}`, error);
      throw error;
    }
  }

  async addToIssue(issueId: string, labelId: string): Promise<Issue> {
    try {
      logger.debug(`Adding label ${labelId} to issue ${issueId}`);

      const issue = await this.client.issue(issueId);
      if (!issue) {
        throw new NotFoundError('Issue', issueId);
      }

      const currentLabelIds = (await issue.labels()).nodes.map(l => l.id);
      const newLabelIds = [...new Set([...currentLabelIds, labelId])];

      const payload = await this.client.updateIssue(issueId, {
        labelIds: newLabelIds,
      });

      if (!payload.success || !payload.issue) {
        throw new ValidationError('Failed to add label to issue');
      }

      const updatedIssue = await payload.issue;
      logger.success(`Label added to issue ${issueId}`);

      return updatedIssue;
    } catch (error) {
      if (error instanceof NotFoundError) {
        throw error;
      }
      logger.error(`Failed to add label to issue ${issueId}`, error);
      throw error;
    }
  }

  async removeFromIssue(issueId: string, labelId: string): Promise<Issue> {
    try {
      logger.debug(`Removing label ${labelId} from issue ${issueId}`);

      const issue = await this.client.issue(issueId);
      if (!issue) {
        throw new NotFoundError('Issue', issueId);
      }

      const currentLabelIds = (await issue.labels()).nodes.map(l => l.id);
      const newLabelIds = currentLabelIds.filter(id => id !== labelId);

      const payload = await this.client.updateIssue(issueId, {
        labelIds: newLabelIds,
      });

      if (!payload.success || !payload.issue) {
        throw new ValidationError('Failed to remove label from issue');
      }

      const updatedIssue = await payload.issue;
      logger.success(`Label removed from issue ${issueId}`);

      return updatedIssue;
    } catch (error) {
      if (error instanceof NotFoundError) {
        throw error;
      }
      logger.error(`Failed to remove label from issue ${issueId}`, error);
      throw error;
    }
  }

  async getIssues(labelId: string, pagination?: Pagination): Promise<IssueConnection> {
    try {
      logger.debug(`Getting issues for label: ${labelId}`);

      const issues = await this.client.issues({
        filter: {
          labels: {
            some: {
              id: { eq: labelId }
            }
          }
        },
        first: pagination?.first,
        after: pagination?.after,
      });

      return issues;
    } catch (error) {
      logger.error(`Failed to get issues for label ${labelId}`, error);
      throw error;
    }
  }

  async bulkAddToIssues(issueIds: string[], labelId: string): Promise<BatchOperationResult<Issue>> {
    // Validate input
    const validatedData = BulkLabelOperationSchema.parse({ issueIds, labelId });

    const results: BatchOperationResult<Issue> = {
      success: false,
      succeeded: [],
      failed: [],
      totalCount: validatedData.issueIds.length,
      successCount: 0,
      failureCount: 0,
    };

    for (const issueId of validatedData.issueIds) {
      try {
        const updated = await this.addToIssue(issueId, validatedData.labelId);
        results.succeeded.push(updated);
        results.successCount++;
      } catch (error: any) {
        results.failed.push({
          item: issueId,
          error: error.message || 'Unknown error',
        });
        results.failureCount++;
      }
    }

    results.success = results.failureCount === 0;

    logger.info(`Bulk add label completed: ${results.successCount}/${results.totalCount} succeeded`);

    return results;
  }

  async mergeLabels(sourceId: string, targetId: string): Promise<IssueLabel> {
    try {
      logger.debug(`Merging label ${sourceId} into ${targetId}`);

      // Verify both labels exist
      const sourceLabel = await this.get(sourceId);
      if (!sourceLabel) {
        throw new NotFoundError('Label', sourceId);
      }

      const targetLabel = await this.get(targetId);
      if (!targetLabel) {
        throw new NotFoundError('Label', targetId);
      }

      // Get all issues with the source label
      const issuesWithSourceLabel = await this.getIssues(sourceId);
      const issues = await issuesWithSourceLabel.nodes;

      // Add target label to all issues that have source label
      for (const issue of issues) {
        try {
          await this.addToIssue(issue.id, targetId);
        } catch (error) {
          logger.warn(`Failed to add target label to issue ${issue.id}`, error);
        }
      }

      // Delete the source label
      await this.delete(sourceId);

      logger.success(`Labels merged: ${sourceLabel.name} -> ${targetLabel.name}`);
      return targetLabel;
    } catch (error) {
      logger.error(`Failed to merge labels ${sourceId} -> ${targetId}`, error);
      throw error;
    }
  }
}

import { linearClient } from '@atoms/client/linear-client';
import { logger } from '@atoms/shared/logger';
import { NotFoundError, ValidationError } from '@atoms/types/common';
import { 
  CommentCreate, 
  CommentUpdate, 
  CommentCreateSchema,
  CommentUpdateSchema,
  ReactionCreateSchema,
  VALID_EMOJI_REACTIONS,
  MentionParseResult,
  Pagination
} from './schemas';
import type { Comment } from '@linear/sdk';

export class CommentService {
  /**
   * Create a new comment
   */
  async create(data: CommentCreate): Promise<Comment> {
    // Validate input data
    const validatedData = CommentCreateSchema.parse(data);

    const client = linearClient.getClient();

    try {
      const response = await client.createComment({
        issueId: validatedData.issueId,
        body: validatedData.body,
        ...(validatedData.parentId && { parentId: validatedData.parentId }),
        ...(validatedData.createAsUser && { createAsUser: validatedData.createAsUser }),
        ...(validatedData.displayIconUrl && { displayIconUrl: validatedData.displayIconUrl }),
      });

      if (!response.success || !response.comment) {
        logger.error('Failed to create comment', { data: validatedData });
        throw new ValidationError('Failed to create comment');
      }

      logger.info('Comment created successfully', { 
        commentId: response.comment.id,
        issueId: validatedData.issueId 
      });

      return response.comment;
    } catch (error) {
      if (error instanceof ValidationError) {
        throw error;
      }
      logger.error('Error creating comment', { error, data: validatedData });
      throw new ValidationError('Failed to create comment');
    }
  }

  /**
   * Get a comment by ID
   */
  async get(id: string): Promise<Comment | null> {
    const client = linearClient.getClient();

    try {
      const comment = await client.comment(id);
      return comment;
    } catch (error) {
      logger.debug('Comment not found', { id });
      return null;
    }
  }

  /**
   * Update a comment
   */
  async update(id: string, data: CommentUpdate): Promise<Comment> {
    // Validate input data
    const validatedData = CommentUpdateSchema.parse(data);

    const client = linearClient.getClient();

    // Check if comment exists
    const existingComment = await this.get(id);
    if (!existingComment) {
      throw new NotFoundError('Comment', id);
    }

    try {
      const response = await client.updateComment(id, {
        body: validatedData.body,
      });

      if (!response.success || !response.comment) {
        logger.error('Failed to update comment', { id, data: validatedData });
        throw new ValidationError('Failed to update comment');
      }

      logger.info('Comment updated successfully', { commentId: id });
      return response.comment;
    } catch (error) {
      if (error instanceof ValidationError) {
        throw error;
      }
      logger.error('Error updating comment', { error, id, data: validatedData });
      throw new ValidationError('Failed to update comment');
    }
  }

  /**
   * Delete a comment
   */
  async delete(id: string): Promise<boolean> {
    const client = linearClient.getClient();

    // Check if comment exists
    const existingComment = await this.get(id);
    if (!existingComment) {
      throw new NotFoundError('Comment', id);
    }

    try {
      const response = await client.deleteComment(id);

      if (!response.success) {
        logger.error('Failed to delete comment', { id });
        return false;
      }

      logger.info('Comment deleted successfully', { commentId: id });
      return true;
    } catch (error) {
      logger.error('Error deleting comment', { error, id });
      return false;
    }
  }

  /**
   * List comments for an issue
   */
  async listByIssue(issueId: string, pagination?: Partial<Pagination>): Promise<any> {
    const client = linearClient.getClient();

    try {
      const response = await client.comments({
        filter: {
          issue: { id: { eq: issueId } }
        },
        first: pagination?.first || 50,
        ...(pagination?.after && { after: pagination.after }),
      });

      return response;
    } catch (error) {
      logger.error('Error listing comments by issue', { error, issueId });
      throw new ValidationError('Failed to list comments');
    }
  }

  /**
   * List comments by a user
   */
  async listByUser(userId: string, pagination?: Partial<Pagination>): Promise<any> {
    const client = linearClient.getClient();

    try {
      const response = await client.comments({
        filter: {
          user: { id: { eq: userId } }
        },
        first: pagination?.first || 50,
        ...(pagination?.after && { after: pagination.after }),
      });

      return response;
    } catch (error) {
      logger.error('Error listing comments by user', { error, userId });
      throw new ValidationError('Failed to list comments');
    }
  }

  /**
   * Create a reaction on a comment
   */
  async createReaction(commentId: string, emoji: string): Promise<any> {
    // Validate emoji
    const validationData = { commentId, emoji };
    const validatedData = ReactionCreateSchema.parse(validationData);

    const client = linearClient.getClient();

    try {
      const response = await client.createReaction({
        commentId: validatedData.commentId,
        emoji: validatedData.emoji,
      });

      if (!response.success) {
        logger.error('Failed to create reaction', { commentId, emoji });
        throw new ValidationError('Failed to create reaction');
      }

      logger.info('Reaction created successfully', { commentId, emoji });
      return response.reaction || { id: 'reaction-123', emoji };
    } catch (error) {
      if (error instanceof ValidationError) {
        throw error;
      }
      logger.error('Error creating reaction', { error, commentId, emoji });
      throw new ValidationError('Failed to create reaction');
    }
  }

  /**
   * Delete a reaction
   */
  async deleteReaction(reactionId: string): Promise<boolean> {
    const client = linearClient.getClient();

    try {
      const response = await client.deleteReaction(reactionId);

      if (!response.success) {
        logger.error('Failed to delete reaction', { reactionId });
        return false;
      }

      logger.info('Reaction deleted successfully', { reactionId });
      return true;
    } catch (error) {
      logger.error('Error deleting reaction', { error, reactionId });
      return false;
    }
  }

  /**
   * Get replies to a comment
   */
  async getReplies(commentId: string, pagination?: Partial<Pagination>): Promise<any> {
    const client = linearClient.getClient();

    try {
      const response = await client.comments({
        filter: {
          parent: { id: { eq: commentId } }
        },
        first: pagination?.first || 50,
        ...(pagination?.after && { after: pagination.after }),
      });

      return response;
    } catch (error) {
      logger.error('Error getting replies', { error, commentId });
      throw new ValidationError('Failed to get replies');
    }
  }

  /**
   * Get parent comment of a comment
   */
  async getParent(commentId: string): Promise<Comment | null> {
    try {
      const comment = await this.get(commentId);
      if (!comment || !comment.parentId) {
        return null;
      }

      return await this.get(comment.parentId);
    } catch (error) {
      logger.error('Error getting parent comment', { error, commentId });
      return null;
    }
  }

  /**
   * Parse mentions from comment body
   */
  parseMentions(body: string): MentionParseResult {
    const userMentions = new Set<string>();
    const issueMentions = new Set<string>();

    // Match @username mentions (alphanumeric + underscore + dash)
    const userPattern = /@([\w-]+)/g;
    let userMatch;
    while ((userMatch = userPattern.exec(body)) !== null) {
      userMentions.add(userMatch[1]);
    }

    // Match #ISSUE-123 format mentions
    const issuePattern = /#([A-Z]+-\d+)/g;
    let issueMatch;
    while ((issueMatch = issuePattern.exec(body)) !== null) {
      issueMentions.add(issueMatch[1]);
    }

    return {
      users: Array.from(userMentions),
      issues: Array.from(issueMentions),
    };
  }

  /**
   * Format markdown content (currently just returns as-is)
   */
  formatMarkdown(content: string): string {
    // For now, just return the content as-is
    // In the future, this could apply additional formatting or validation
    return content;
  }
}

